// Real-world deblur demo: BoofCV face_gaussian sample.
//
// Uses the public `deblurAnyImage` API with `sigma: 'auto'` ŌĆö the
// Žå-attractor selects Žā via the goldenSpacedGrid + interfere() fold,
// ŌłÜ5-Binet residual minimization, and Newton refinement. RGB mode so
// the recovered PNG is the actual colour image, not luminance only.
//
// Not a smoke test ŌĆö there is no sharp reference, so this cannot assert
// PSNR. It writes the recovered PNG to .qa-artifacts/scratch/ and prints
// the attractor trace so the picked Žā and per-candidate residuals are
// visible.
//
// Run with: pnpm exec vitest run __tests__/real-blur-demo.test.ts

import { beforeAll, describe, expect, it } from 'vitest';
import { dirname, join, resolve } from 'path';
import { fileURLToPath } from 'url';
import { mkdir, writeFile } from 'fs/promises';

import { deblurAnyImage, encodeRecoveredAsPNG } from '../src/deblur-any-image';
import { forkRaceFoldDeblur } from '../src/forkraceFoldDeblur';
import { TOWER_CEILINGS } from '../src/spectral-noise-monitor';
import { ensureFaceJpeg } from './helpers/deblur-fixtures';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);
const REPO_ROOT = resolve(__dirname, '../../../..');
const SCRATCH = join(REPO_ROOT, '.qa-artifacts/scratch');

describe('deblurAnyImage on real-world BoofCV face_gaussian', () => {
  beforeAll(async () => {
    await ensureFaceJpeg();
  });

  it('auto-selects Žā via Žå-attractor and writes recovered RGB PNG', async () => {
    await mkdir(SCRATCH, { recursive: true });
    const inputPath = join(SCRATCH, 'kodim17-face-gaussian-full.jpg');

    const result = await deblurAnyImage(inputPath, {
      sigma: 'auto',
      channelMode: 'rgb',
    });

    const outPath = join(SCRATCH, 'kodim17-face-deblurred-auto.png');
    const png = await encodeRecoveredAsPNG(result);
    await writeFile(outPath, png);

    const candidates = result.attractor!.candidates;
    // eslint-disable-next-line no-console
    console.log(
      `\n[deblurAnyImage auto] BoofCV face (${result.width}x${result.height}, ${result.channels}ch)`,
    );
    // eslint-disable-next-line no-console
    console.log(
      `  selectedSigma=${result.attractor!.selectedSigma.toFixed(3)}  ` +
        `refinedSigma=${result.selectedSigma.toFixed(3)}  ` +
        `bestIdx=${result.attractor!.bestCandidateIndex}`,
    );
    // eslint-disable-next-line no-console
    console.log('  Žā-grid    highBandE       deficitRatio  Binet residual  excluded');
    for (const c of candidates) {
      const e = c.highBandEnergy;
      // eslint-disable-next-line no-console
      console.log(
        `  ${c.sigma.toFixed(3).padStart(7)}  ${e.toExponential(3).padStart(11)}  ` +
          `${c.deficitRatio.toFixed(4).padStart(8)}  ${c.binetResidual.toFixed(4).padStart(10)}  ` +
          `${c.excludedFromAttractor ? 'yes' : 'no'}`,
      );
    }
    // eslint-disable-next-line no-console
    console.log('  per-channel:');
    for (let c = 0; c < result.perChannel.length; c++) {
      const r = result.perChannel[c]!;
      // eslint-disable-next-line no-console
      console.log(
        `    [ch ${c}] face=${r.face} reason=${r.reason} ` +
          `score=${r.carrierBuley.score} ` +
          `low╬ö=${r.lowBandDelta.toExponential(2)} high╬ö=${r.highBandDelta.toExponential(2)}`,
      );
    }
    // eslint-disable-next-line no-console
    console.log(`  ŌåÆ ${outPath}`);

    expect(result.attractor!.candidates.length).toBeGreaterThanOrEqual(7);
    expect(result.attractor!.bestCandidateIndex).toBeGreaterThanOrEqual(0);
    expect(result.selectedSigma).toBeGreaterThan(0);
    expect(Number.isFinite(result.selectedSigma)).toBe(true);
    for (const ch of result.perChannel) {
      expect(ch.carrierBuley.score).toBeLessThanOrEqual(TOWER_CEILINGS.hexon);
    }
  }, 120_000);

  it('respects an explicit Žā override', async () => {
    const inputPath = join(SCRATCH, 'kodim17-face-gaussian-full.jpg');
    const result = await deblurAnyImage(inputPath, {
      sigma: 2.0,
      channelMode: 'rgb',
    });
    expect(result.selectedSigma).toBe(2.0);
    expect(result.attractor).toBeUndefined();
    const outPath = join(SCRATCH, 'kodim17-face-deblurred-sigma2p0.png');
    await writeFile(outPath, await encodeRecoveredAsPNG(result));
    // eslint-disable-next-line no-console
    console.log(`[deblurAnyImage Žā=2.0] ŌåÆ ${outPath}`);
  }, 60_000);

  it('auto-psfSize removes Gibbs banding at high Žā vs fixed-11 baseline', async () => {
    // Direct A/B on Žā=3.0 ŌĆö the Žā that produced the most visible banding in
    // the old Žā-sweep demo (kodim17-face-recovered-sigma3p0.png). Both runs
    // use the new mirror-padded pipeline; only psfSize differs.
    const inputPath = join(SCRATCH, 'kodim17-face-gaussian-full.jpg');

    const old11 = await deblurAnyImage(inputPath, {
      sigma: 3.0,
      channelMode: 'luminance',
      psfSize: 11,
    });
    const newAuto = await deblurAnyImage(inputPath, {
      sigma: 3.0,
      channelMode: 'luminance',
      // psfSize omitted ŌåÆ recommendPsfSize(3) = 19
    });

    await writeFile(
      join(SCRATCH, 'kodim17-face-sigma3-psf11.png'),
      await encodeRecoveredAsPNG(old11),
    );
    await writeFile(
      join(SCRATCH, 'kodim17-face-sigma3-psfauto.png'),
      await encodeRecoveredAsPNG(newAuto),
    );

    // eslint-disable-next-line no-console
    console.log(
      `[psfSize comparison Žā=3.0]\n` +
        `  psf=11  ŌåÆ ${join(SCRATCH, 'kodim17-face-sigma3-psf11.png')}\n` +
        `  psf=19  ŌåÆ ${join(SCRATCH, 'kodim17-face-sigma3-psfauto.png')}`,
    );
  }, 120_000);

  it('luminance mode carries original chroma forward (watercolor effect)', async () => {
    const inputPath = join(SCRATCH, 'kodim17-face-gaussian-full.jpg');
    const result = await deblurAnyImage(inputPath, {
      sigma: 'auto',
      channelMode: 'luminance',
    });
    const outPath = join(SCRATCH, 'kodim17-face-deblurred-luminance.png');
    await writeFile(outPath, await encodeRecoveredAsPNG(result));
    // eslint-disable-next-line no-console
    console.log(
      `[deblurAnyImage luminance Žā=${result.selectedSigma.toFixed(3)}] ŌåÆ ${outPath}`,
    );
    expect(result.perChannel).toHaveLength(1);
    expect(result.channels).toBe(3);
  }, 120_000);

  it('end-to-end with all opportunities engaged (auto noise + bilateral + RL + chroma clamp)', async () => {
    const inputPath = join(SCRATCH, 'kodim17-face-gaussian-full.jpg');
    const result = await deblurAnyImage(inputPath, {
      sigma: 'auto',
      channelMode: 'luminance',
      method: 'richardson-lucy',
      iterations: 20,
      noiseFloor: 'auto',
      bilateralPostpass: { sigmaSpatial: 2.0, sigmaIntensity: 0.06 },
      chromaRatioClamp: [0.6, 1.7],
    });
    const outPath = join(SCRATCH, 'kodim17-face-deblurred-full-stack.png');
    await writeFile(outPath, await encodeRecoveredAsPNG(result));
    // eslint-disable-next-line no-console
    console.log(
      `[full-stack Žā=${result.selectedSigma.toFixed(3)} ` +
        `noiseFloor=${result.noiseFloorUsed.toExponential(2)} ` +
        `method=${result.methodUsed} bilateral=${result.bilateralApplied}] ŌåÆ ${outPath}`,
    );
    expect(result.methodUsed).toBe('richardson-lucy');
    expect(result.bilateralApplied).toBe(true);
    expect(result.noiseFloorUsed).toBeGreaterThan(0);
  }, 180_000);

  it('FRF ensemble ŌĆö fork {Wiener@Žā-grid, RL, bilateral} ŌåÆ race ŌåÆ fold by Bule deficit weight', async () => {
    const inputPath = join(SCRATCH, 'kodim17-face-gaussian-full.jpg');

    const result = await forkRaceFoldDeblur({
      input: inputPath,
      configs: [
        { label: 'wiener-sigma-1.5',          options: { sigma: 1.5,  method: 'wiener',          channelMode: 'luminance' } },
        { label: 'wiener-sigma-2.0',          options: { sigma: 2.0,  method: 'wiener',          channelMode: 'luminance' } },
        { label: 'wiener-sigma-2.5',          options: { sigma: 2.5,  method: 'wiener',          channelMode: 'luminance' } },
        { label: 'wiener-sigma-3.0',          options: { sigma: 3.0,  method: 'wiener',          channelMode: 'luminance' } },
        { label: 'rl-sigma-2.0-iter15',       options: { sigma: 2.0,  method: 'richardson-lucy', iterations: 15, channelMode: 'luminance' } },
        { label: 'wiener-auto-bilateral',     options: { sigma: 'auto', method: 'wiener', bilateralPostpass: true, channelMode: 'luminance' } },
      ],
      concurrency: 6,
    });

    const outPath = join(SCRATCH, 'kodim17-face-frf-ensemble.png');
    await writeFile(outPath, await encodeRecoveredAsPNG({
      recovered: result.recovered,
      width: result.width,
      height: result.height,
      channels: result.channels,
      // Stub the rest of DeblurAnyImageResult for the encoder helper.
      selectedSigma: 0,
      noiseFloorUsed: 0,
      methodUsed: 'wiener',
      bilateralApplied: false,
      perChannel: [],
      analysis: undefined as never,
    }));

    // eslint-disable-next-line no-console
    console.log(
      `[FRF ensemble] survivors=${result.fold.survivors}/${result.fold.rounds}  ` +
        `rejected=${result.fold.rejected}  totalWeight=${result.fold.totalWeight}\n` +
        result.candidates.map((c) =>
          `    [rank=${c.rank.toString().padStart(2)} w=${c.buleyWeight}] ${c.label.padEnd(28)} ` +
          `Žā=${c.selectedSigma.toFixed(3)}  method=${c.methodUsed.padEnd(15)}  ` +
          `|residual|=${Math.abs(c.binetResidual).toExponential(2)}  ` +
          `score=${c.maxChannelScore}${c.rejectedByCeiling ? '  REJECTED' : ''}`,
        ).join('\n') +
        `\n  ŌåÆ ${outPath}`,
    );

    expect(result.fold.survivors).toBeGreaterThanOrEqual(4);
    expect(result.fold.totalWeight).toBeGreaterThan(0);
    expect(result.candidates).toHaveLength(6);
    // Best candidate (rank=0) gets the maximum weight = R+1.
    const best = result.candidates.find((c) => c.rank === 0);
    expect(best).toBeDefined();
    expect(best!.buleyWeight).toBe(result.fold.survivors + 1);
  }, 180_000);

  it('Wiener with bilateral post-pass alone (banding mitigation, no method switch)', async () => {
    const inputPath = join(SCRATCH, 'kodim17-face-gaussian-full.jpg');
    const result = await deblurAnyImage(inputPath, {
      sigma: 'auto',
      channelMode: 'luminance',
      bilateralPostpass: true,
    });
    const outPath = join(SCRATCH, 'kodim17-face-deblurred-wiener-bilateral.png');
    await writeFile(outPath, await encodeRecoveredAsPNG(result));
    // eslint-disable-next-line no-console
    console.log(
      `[wiener+bilateral Žā=${result.selectedSigma.toFixed(3)}] ŌåÆ ${outPath}`,
    );
    expect(result.bilateralApplied).toBe(true);
    expect(result.methodUsed).toBe('wiener');
  }, 120_000);
});
